import { IMessageComposer } from '@nitrots/nitro-renderer';

export class HireCorporationMemberComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor(corporationId: number, username: string) {
        this._data = [corporationId, username];
        console.log('[📤] HireCorporationMemberComposer:', this._data);
    }

    public getMessageArray(): any[] {
        return this._data;
    }
    public dispose(): void {
        /* no-op */
    }
}
